const body = $input.first().json.body || $input.first().json;
const chunks = body.chunks || [];
console.log(`Batch ${body.batch_number}/${body.total_batches} — ${chunks.length} chunks`);
return chunks.map(chunk => ({ json: chunk }));

const msg = $input.first().json;
const chatId = msg.message.chat.id;
const question = msg.message.text;
const firstName = msg.message.from.first_name || 'there';

// Skip /start command
if (question.startsWith('/start')) {
  return [{ json: { is_start: true, chat_id: chatId, first_name: firstName, question: '' } }];
}

return [{ json: { is_start: false, chat_id: chatId, first_name: firstName, question } }];

const results  = $input.first().json.result || [];
const question = $('Extract Message').first().json.question;
const chatId   = $('Extract Message').first().json.chat_id;

// No relevant results found
if (results.length === 0) {
  return [{ json: {
    chat_id: chatId,
    prompt: '',
    no_result: true
  }}];
}

const context = results
  .map((r, i) => {
    const p = r.payload;
    return `[${i+1}] Source: ${p.topic} (${p.source_file}, page ${p.page})\n${p.text}`;
  })
  .join('\n\n---\n\n');

const prompt = `You are a helpful HR assistant for company policies.
Answer the employee's question based ONLY on the policy documents below.
If the answer is not in the documents, say you could not find it and suggest contacting HR.
Always mention which policy document your answer comes from.
Keep your answer concise and friendly. Use plain text only, no markdown.

POLICY DOCUMENTS:
${context}

EMPLOYEE QUESTION: ${question}

ANSWER:`;

return [{ json: { chat_id: chatId, prompt, no_result: false } }];

const item = $input.first().json;

const chatId = item.chat_id
  || $('Extract Message').first().json.chat_id;

const answer = item.answer || item.text || 'Sorry, I could not generate a response.';

return [{ json: { chat_id: chatId, answer } }];

const item = $input.item.json;

const id = Math.abs(item.chunk_id.split('').reduce((a, b) => {
  a = ((a << 5) - a) + b.charCodeAt(0);
  return a & a;
}, 0));

const payload = {
  points: [
    {
      id: id,
      vector: item.embedding,
      payload: {
        chunk_id: item.chunk_id,
        source_file: item.source_file,
        topic: item.topic,
        page: item.page,
        text: item.text
      }
    }
  ]
};

await this.helpers.httpRequest({
  method: 'PUT',
  url: 'http://YOUR_QDRANT_IP:6333/collections/policy_chunks/points',
  headers: { 'Content-Type': 'application/json' },
  body: JSON.stringify(payload),
});

return { json: { saved: "ok" } };

const embedding = $input.first().json.embedding;
const vector = embedding.values || embedding;

const response = await this.helpers.httpRequest({
  method: 'POST',
  url: 'http://YOUR_QDRANT_IP:6333/collections/policy_chunks/points/search',
  headers: { 'Content-Type': 'application/json' },
  body: JSON.stringify({
    vector: vector,
    top: 5,
    with_payload: true,
    score_threshold: 0.3
  }),
});

return [{ json: response }];

// Replace with your Groq API key
// Get a free key at: https://console.groq.com
const GROQ_API_KEY = "YOUR_GROQ_API_KEY_HERE";

const promptNode = $input.first().json;
const prompt = promptNode.prompt;
const chatId = promptNode.chat_id;

let answer = 'Sorry, could not generate a response. Please try again.';

try {
  const response = await this.helpers.httpRequest({
    method: 'POST',
    url: 'https://api.groq.com/openai/v1/chat/completions',
    headers: {
      'Content-Type': 'application/json',
      'Authorization': `Bearer ${GROQ_API_KEY}`
    },
    body: JSON.stringify({
      model: 'llama-3.1-8b-instant',
      messages: [{ role: 'user', content: prompt }],
      temperature: 0.2,
      max_tokens: 1024
    }),
  });
  answer = response?.choices?.[0]?.message?.content || answer;
} catch(e) {
  answer = 'Sorry, could not generate a response. Error: ' + e.message;
}

return [{ json: { chat_id: chatId, answer } }];
